+
+    #[test]
+    fn format_tier_danger() {
+        let result = format_tier(&SafetyTier::Danger);
+        assert!(result.to_string().contains("DANGER"));
+    }
+
+    #[test]
+    fn format_tier_critical() {
+        let result = format_tier(&SafetyTier::Critical);
