+        let json = serde_json::to_string(&decision).unwrap();
+
+        // Should not contain these optional fields when None
+        assert!(!json.contains("remediation"));
+        assert!(!json.contains("rule_id"));
+        assert!(!json.contains("pack"));
+    }
