+
+    #[test]
+    fn dcg_guard_new() {
+        let guard = DcgGuard::new(
+            PathBuf::from("/usr/bin/dcg"),
+            vec!["default".to_string(), "extra".to_string()],
+            "json".to_string(),
+        );
+
+        assert_eq!(guard.dcg_bin, PathBuf::from("/usr/bin/dcg"));
+        assert_eq!(guard.packs.len(), 2);
+        assert_eq!(guard.explain_format, "json");
