+
+        // Empty commands are always allowed
+        let decision = guard.evaluate_command("").unwrap();
+        assert!(decision.allowed);
+        assert_eq!(decision.reason, "empty command");
+    }
+
+    #[test]
+    fn dcg_guard_whitespace_only_allowed() {
+        let guard = DcgGuard::new(
